// =========================================================================
// UNIFORMS & SETTINGS
// =========================================================================

uniform sampler2D uPreviousFrame;
uniform vec2 uResolution;
uniform vec2 uMouse;

// --- SHARPEN SETTINGS ---
uniform float sharpenAmount;    // Strength of the sharpen effect inside the ring

// --- BLUR SETTINGS ---
uniform float uRadius;          // Radius of the clear focus ring
uniform float uSamples;         // Blur Quality (Iteration count)
uniform float uBlurStrength;    // Blur Intensity
uniform int uShapeType;         // 0=Circle, 1=Horizontal, 2=Vertical

// =========================================================================
// HELPER FUNCTIONS
// =========================================================================

// Gaussian Weight for smooth blur falloff
float gaussian(float x, float sigma) {
    float s2 = 2.0 * sigma * sigma;
    if (s2 < 0.00001) return 1.0; 
    return exp(-(x * x) / s2);
}

// =========================================================================
// MAIN SHADER
// =========================================================================

void mainImage(const in vec4 inputColor, const in vec2 uv, out vec4 outputColor) {

    vec2 pixel = 1.0 / uResolution;

    // ---------------------------------------------------------------------
    // STEP 1: CALCULATE SHARPENED IMAGE (The "Focus" Area)
    // ---------------------------------------------------------------------

    // 3x3 Convolution Kernel for Sharpening
    vec4 P0 = texture2D(uPreviousFrame, uv + vec2(-pixel.x, -pixel.y));
    vec4 P1 = texture2D(uPreviousFrame, uv + vec2(0.0, -pixel.y));
    vec4 P2 = texture2D(uPreviousFrame, uv + vec2(pixel.x, -pixel.y));
    vec4 P3 = texture2D(uPreviousFrame, uv + vec2(-pixel.x, 0.0));
    vec4 P4 = texture2D(uPreviousFrame, uv); // Center Pixel
    vec4 P5 = texture2D(uPreviousFrame, uv + vec2(pixel.x, 0.0));
    vec4 P6 = texture2D(uPreviousFrame, uv + vec2(-pixel.x, pixel.y));
    vec4 P7 = texture2D(uPreviousFrame, uv + vec2(0.0, pixel.y));
    vec4 P8 = texture2D(uPreviousFrame, uv + vec2(pixel.x, pixel.y));

    // Apply Sharpen Formula: Center * Strength - Neighbors * Strength
    vec4 sharpColor = P4 * (1.0 + 8.0 * sharpenAmount) - (P0 + P1 + P2 + P3 + P5 + P6 + P7 + P8) * sharpenAmount;
    sharpColor.a = 1.0; // Ensure alpha stays solid

    // ---------------------------------------------------------------------
    // STEP 2: CALCULATE BLUR OR OUTPUT SHARP (Based on Mouse Distance)
    // ---------------------------------------------------------------------

    vec4 finalColor;
    float distToMouse = distance(uv, uMouse);

    // If we are inside the focus ring, show the sharp image immediately
    if (distToMouse < uRadius) {
        finalColor = sharpColor;
    } 
    // If we are outside, calculate the blur
    else {
        vec4 blurredColor = vec4(0.0);
        float totalWeight = 0.0;
        int blurSamples = int(uSamples);

        // Calculate blur strength based on distance from the ring edge
        // The further away, the blurrier it gets
        float sigma = max(0.001, uBlurStrength * (distToMouse - uRadius)); 

        // Blur Loop
        for (int i = 0; i < 50; ++i) { // Hard limit of 50 for safety
            if (i >= blurSamples) break;

            vec2 offset;

            // Calculate Offset based on Shape Type
            if (uShapeType == 0) { // Circular (Bokeh style)
                float a = float(i) / float(blurSamples) * 6.28318;
                offset = vec2(cos(a), sin(a)) * sigma;
            } else if (uShapeType == 1) { // Horizontal (Motion blur)
                offset = vec2(float(i) - float(blurSamples)/2.0, 0.0) / float(blurSamples) * sigma * 2.0;
            } else { // Vertical (Motion blur)
                offset = vec2(0.0, float(i) - float(blurSamples)/2.0) / float(blurSamples) * sigma * 2.0;
            }

            // Apply Gaussian Weight
            float weight = gaussian(length(offset), sigma);

            // We blur the ORIGINAL frame (P4/texture), not the sharpened one, for smoothness
            blurredColor += texture2D(uPreviousFrame, uv + offset) * weight;
            totalWeight += weight;
        }

        // Normalize the blur
        if (totalWeight > 0.001) {
            finalColor = blurredColor / totalWeight;
        } else {
            finalColor = P4; // Fallback to original if weight is zero
        }
    }

    outputColor = finalColor;
}
